"use client"

import { useState, useEffect } from "react"
import { getUser } from "@/lib/auth"
// ... outros imports que você já tenha

/**
 * Componente de Navegação Lateral.
 * Gerencia a exibição de rotas, identidade do usuário e estado de montagem para evitar erros de SSR.
 */
export function Navigation() {
  const user = getUser()
  const [mounted, setMounted] = useState(false)

  /**
   * Ciclo de vida para sincronização com o cliente.
   * Garante que dados dependentes do navegador (como o nome do usuário) 
   * só sejam renderizados após a hidratação completa.
   */
  useEffect(() => {
    setMounted(true)
  }, [])

  return (
    <nav className="border-r bg-card h-full w-64 flex flex-col">
      <div className="p-6 border-b border-border">
        <h1 className="text-2xl font-bold text-foreground">FinPlan</h1>
        
        {/* A renderização do nome é condicionada ao estado 'mounted'.
          Isso previne a divergência entre o HTML do servidor e do cliente (Hydration Error).
        */}
        {mounted && user && (
          <p className="text-sm text-muted-foreground mt-1 truncate">
            {user.nome}
          </p>
        )}
      </div>

      {/* ... restante dos itens do menu (NAV_ITEMS.map, etc) */}
    </nav>
  )
}